  ('fire-eq-tech-moex-00956', 'fire-eq-tech', 'fire-eq-tech-moex-107-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依各類場所消防安全設備設置標準規定，緊急照明設備除內置蓄電池外，應連接緊急電源，其蓄電池容 量應能使其持續動作 a 分鐘以上。但採蓄電池設備與緊急發電機併設方式時，其容量應能使其持續動作 分別為b分鐘及c分鐘以上，請問下列何者正確？', '["a = 10", "b = 30", "c = 10", "a+b+c = 70"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "8afc7628421a", "answer_pdf_sha1": "3bf6e8a0f9cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "502", "s": "0909", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
